func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	logger := zap.L().Named("Insert")

	for jj := range oris {
		// Collect non-empty assign indices
		var nonEmpty []int
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			if dispatch.Assigns[ii].StationsLen > 0 {
				nonEmpty = append(nonEmpty, ii)
			}
		}

		// Compute heuristic score for each non-empty assign:
		// distance from last station to pickup + time difference (waiting time)
		scores := make([]float64, len(nonEmpty))
		for idx, ii := range nonEmpty {
			lastIdx := dispatch.Assigns[ii].StationsLen - 1
			lastSta := dispatch.Assigns[ii].Stations[lastIdx]
			dist := cal_dis(lastSta, oris[jj])
			timeDiff := 0
			if oris[jj].TimeStart > dispatch.Assigns[ii].TimeCurrent {
				timeDiff = oris[jj].TimeStart - dispatch.Assigns[ii].TimeCurrent
			}
			scores[idx] = dist + float64(timeDiff)
		}
		sort.Slice(nonEmpty, func(i, j int) bool {
			return scores[i] < scores[j]
		})

		// Build insertion order: sorted non-empty first, then empty assigns
		order := make([]int, 0, MAXASSIGNS)
		order = append(order, nonEmpty...)
		for ii := dispatch.AssignsLen; ii < MAXASSIGNS; ii++ {
			order = append(order, ii)
		}

		// Try insertion in the computed order
		for _, ii := range order {
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[ii].Cost = -1
			} else {
				dispatch.Assigns[ii].GenRoute()
			}

			if dispatch.Assigns[ii].Cost < 0 {
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			} else {
				if ii >= dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
				break
			}

			// If we reach an empty assign and insertion fails, log and stop trying this ship
			if ii >= dispatch.AssignsLen {
				logger.Warn(
					"Cannot Insert",
					zap.Int("ship", total_ship+jj),
					zap.Int("non_empty", len(nonEmpty)),
					zap.Int("assigns_len", dispatch.AssignsLen),
				)
				fmt.Println(oris[jj], dess[jj])
				dispatch.Assigns[dispatch.AssignsLen].PrettyPrint()
				break
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}
